create table dirkspzm32.isi_scan_log (
    sid             varchar2(2 char) not null enable,
    isi_scan_log_id number(*, 0) not null enable,
    log_time        timestamp(6),
    scanner_name    varchar2(255 char),
    scanner_read    varchar2(100 char),
    scanner_cmd     varchar2(100 char),
    res_id          number(*, 0),
    res_status_id   number(*, 0),
    res_aufgabe     varchar2(1 char),
    leitzahl        number,
    pers_nr         number,
    lte_id          varchar2(19 char),
    lhm_id          varchar2(19 char),
    scan_ok         varchar2(1 char),
    error_txt       varchar2(2550 char)
);

alter table dirkspzm32.isi_scan_log
    add constraint pk_isi_scan_log primary key ( sid,
                                                 isi_scan_log_id )
        using index enable;


